objects.draw:
function(ctx, obj) {
  ctx.save();
  if (obj.rotationAngle) {
    ctx.translate(obj.x, obj.y);
    ctx.rotate(obj.rotationAngle);
    ctx.translate(-obj.x, -obj.y);
  }
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, 2 * Math.PI);
  const grad = ctx.createLinearGradient(obj.x - obj.w, obj.y - obj.w, obj.x + obj.w, obj.y + obj.w);
  grad.addColorStop(0, '#94a3b8');
  grad.addColorStop(0.5, '#cbd5e1');
  grad.addColorStop(1, '#64748b');
  ctx.fillStyle = grad;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w - 5, 0, 2 * Math.PI);
  ctx.fillStyle = '#1e293b';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w * 0.2, 0, 2 * Math.PI);
  ctx.fillStyle = '#0f172a';
  ctx.fill();
  ctx.beginPath();
  for (let i = 0; i < 6; i++) {
    const angle = (i * Math.PI * 2) / 6;
    ctx.moveTo(obj.x + Math.cos(angle) * obj.w * 0.3, obj.y + Math.sin(angle) * obj.w * 0.3);
    ctx.lineTo(obj.x + Math.cos(angle) * obj.w * 0.85, obj.y + Math.sin(angle) * obj.w * 0.85);
  }
  ctx.strokeStyle = '#fbbf24';
  ctx.lineWidth = 2;
  ctx.stroke();
  ctx.restore();
  if (obj.leftMassObj && obj.rightMassObj) {
    ctx.save();
    ctx.beginPath();
    const leftMassY = obj.leftMassObj.y + obj.leftMassObj.w;
    const leftAttachX = obj.x - obj.w * 0.65;
    const leftAttachY = obj.y + obj.w * 0.3;
    ctx.moveTo(leftAttachX, leftAttachY);
    ctx.quadraticCurveTo(obj.x - obj.w * 0.4, (leftAttachY + leftMassY) / 2, obj.x - 12, leftMassY - 8);
    const rightMassY = obj.rightMassObj.y + obj.rightMassObj.w;
    const rightAttachX = obj.x + obj.w * 0.65;
    const rightAttachY = obj.y + obj.w * 0.3;
    ctx.moveTo(rightAttachX, rightAttachY);
    ctx.quadraticCurveTo(obj.x + obj.w * 0.4, (rightAttachY + rightMassY) / 2, obj.x + 12, rightMassY - 8);
    ctx.strokeStyle = obj.ropeColor;
    ctx.lineWidth = obj.ropeWidth;
    ctx.lineCap = 'round';
    ctx.stroke();
    ctx.restore();
  }
}

objects.update:
function(obj, dt) {
  if (!obj.leftMassObj || !obj.rightMassObj) return;
  const m1 = obj.leftMass;
  const m2 = obj.rightMass;
  const I = obj.momentOfInertia;
  const r = obj.w / 100;
  const g = Lab.state.gravity;
  const friction = obj.friction;
  const ropeFriction = obj.ropeFriction;
  const denominator = m1 + m2 + I / (r * r);
  let a = (m2 - m1) * g / denominator;
  if (Math.abs(obj.velocity) > 0.01) {
    const frictionForce = friction * (m1 + m2) * g;
    const frictionAcc = frictionForce / denominator;
    if (a > 0) a = Math.max(0, a - frictionAcc);
    else if (a < 0) a = Math.min(0, a + frictionAcc);
  }
  const angularFriction = Math.abs(obj.angularVelocity) * ropeFriction;
  obj.velocity = (obj.velocity || 0) + a * dt;
  obj.velocity *= (1 - friction * dt * 0.5);
  obj.angularVelocity = (obj.angularVelocity || 0) + (a / r) * dt;
  obj.angularVelocity *= (1 - angularFriction * dt);
  obj.rotationAngle = (obj.rotationAngle || 0) + obj.angularVelocity * dt * 30;
  let leftNewY = (obj.leftPosition || 400) - obj.velocity * dt;
  let rightNewY = (obj.rightPosition || 400) + obj.velocity * dt;
  const minY = 80;
  const maxY = 620;
  leftNewY = Math.max(minY, Math.min(maxY, leftNewY));
  rightNewY = Math.max(minY, Math.min(maxY, rightNewY));
  obj.leftPosition = leftNewY;
  obj.rightPosition = rightNewY;
  if (obj.leftMassObj) obj.leftMassObj.y = obj.leftPosition - obj.leftMassObj.w;
  if (obj.rightMassObj) obj.rightMassObj.y = obj.rightPosition - obj.rightMassObj.w;
}

objects.draw:
function(ctx, obj) {
  ctx.save();
  ctx.shadowBlur = 8;
  ctx.shadowColor = 'rgba(0,0,0,0.3)';
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, 2 * Math.PI);
  const grad = ctx.createRadialGradient(obj.x - obj.w * 0.3, obj.y - obj.w * 0.3, obj.w * 0.2, obj.x, obj.y, obj.w);
  grad.addColorStop(0, obj.fill);
  grad.addColorStop(1, obj.stroke);
  ctx.fillStyle = grad;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(obj.x - obj.w * 0.25, obj.y - obj.w * 0.25, obj.w * 0.15, 0, 2 * Math.PI);
  ctx.fillStyle = 'rgba(255,255,255,0.6)';
  ctx.fill();
  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold ' + Math.max(10, obj.w * 0.6) + 'px monospace';
  ctx.shadowBlur = 2;
  ctx.fillText(obj.mass + 'kg', obj.x - 12, obj.y + 6);
  ctx.beginPath();
  ctx.arc(obj.x, obj.y - obj.w, 4, 0, 2 * Math.PI);
  ctx.fillStyle = '#8b5cf6';
  ctx.fill();
  ctx.fillStyle = '#ffffff';
  ctx.beginPath();
  ctx.arc(obj.x, obj.y - obj.w, 2, 0, 2 * Math.PI);
  ctx.fill();
  ctx.restore();
}

tools.action:
function() {
  const centerX = Lab.state.W / 2;
  const pulleyY = 130;
  const massStartY = 450;
  const existing = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (existing) {
    if (confirm('Já existe uma máquina de Atwood. Deseja recriar?')) {
      Lab.objects.remove(existing.id);
      const leftMass = Lab.state.objects.find(o => o.pluginId === 'atwood_mass' && o.x < centerX);
      const rightMass = Lab.state.objects.find(o => o.pluginId === 'atwood_mass' && o.x > centerX);
      if (leftMass) Lab.objects.remove(leftMass.id);
      if (rightMass) Lab.objects.remove(rightMass.id);
    } else { return; }
  }
  const pulley = Lab.objects.add({
    type: 'rect',
    pluginId: 'atwood_pulley',
    x: centerX - 22,
    y: pulleyY - 22,
    w: 45,
    h: 45,
    mass: 2,
    momentOfInertia: 0.6,
    friction: 0.04,
    ropeFriction: 0.015,
    fill: '#cbd5e1',
    stroke: '#475569',
    lineWidth: 2,
    static: true,
    leftMass: 1,
    rightMass: 1.5,
    leftPosition: massStartY,
    rightPosition: massStartY,
    ropeColor: '#8b5cf6',
    ropeWidth: 4,
    velocity: 0,
    angularVelocity: 0,
    rotationAngle: 0
  });
  const leftMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX - 100,
    y: massStartY - 14,
    w: 28,
    mass: 1,
    fill: '#3b82f6',
    stroke: '#1d4ed8',
    lineWidth: 2,
    collidable: true
  });
  const rightMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX + 100,
    y: massStartY - 14,
    w: 28,
    mass: 1.5,
    fill: '#ef4444',
    stroke: '#dc2626',
    lineWidth: 2,
    collidable: true
  });
  const pulleyObj = Lab.objects.get(pulley);
  pulleyObj.leftMassObj = Lab.objects.get(leftMass);
  pulleyObj.rightMassObj = Lab.objects.get(rightMass);
  pulleyObj.leftMass = 1;
  pulleyObj.rightMass = 1.5;
  pulleyObj.leftPosition = massStartY;
  pulleyObj.rightPosition = massStartY;
  const diff = Math.abs(1.5 - 1);
  const g = 9.8;
  const I = 0.6;
  const r = 0.45;
  const denominator = 1 + 1.5 + I / (r * r);
  const acceleration = (diff * g) / denominator;
  alert('✅ Máquina de Atwood criada!\n\nMassa esquerda: 1.0 kg\nMassa direita: 1.5 kg\nAceleração teórica: ' + acceleration.toFixed(3) + ' m/s²\n\nSelecione a roldana para ajustar os parâmetros!');
}

function() {
  const atwoodPulley = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!atwoodPulley) { alert('❌ Nenhuma máquina de Atwood encontrada.'); return; }
  const m1 = parseFloat(prompt('Massa esquerda (kg):', atwoodPulley.leftMass || 1));
  const m2 = parseFloat(prompt('Massa direita (kg):', atwoodPulley.rightMass || 1.5));
  if (!isNaN(m1) && !isNaN(m2) && m1 > 0 && m2 > 0) {
    atwoodPulley.leftMass = m1;
    atwoodPulley.rightMass = m2;
    if (atwoodPulley.leftMassObj) atwoodPulley.leftMassObj.mass = m1;
    if (atwoodPulley.rightMassObj) atwoodPulley.rightMassObj.mass = m2;
    const diff = Math.abs(m1 - m2);
    const g = Lab.state.gravity;
    const I = atwoodPulley.momentOfInertia;
    const r = atwoodPulley.w / 100;
    const denominator = m1 + m2 + I / (r * r);
    const acceleration = (diff * g) / denominator;
    alert('✅ Massas ajustadas!\nEsquerda: ' + m1 + ' kg\nDireita: ' + m2 + ' kg\nAceleração: ' + acceleration.toFixed(3) + ' m/s²');
  }
}

function() {
  const atwoodPulley = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!atwoodPulley) { alert('❌ Nenhuma máquina de Atwood encontrada.'); return; }
  const ropeFriction = parseFloat(prompt('Atrito da corda (0-0.3):', atwoodPulley.friction || 0.04));
  const pulleyFriction = parseFloat(prompt('Atrito da roldana (0-0.2):', atwoodPulley.ropeFriction || 0.015));
  if (!isNaN(ropeFriction) && !isNaN(pulleyFriction)) {
    atwoodPulley.friction = Math.max(0, Math.min(0.3, ropeFriction));
    atwoodPulley.ropeFriction = Math.max(0, Math.min(0.2, pulleyFriction));
    alert('✅ Atritos ajustados!\nAtrito corda: ' + atwoodPulley.friction + '\nAtrito roldana: ' + atwoodPulley.ropeFriction);
  }
}

